// Normalize the LLM's tool args into a uniform { command } shape.
// Mirrors postgres-named-queries 'Normalize Input' (Stage 113): the toolWorkflow
// node uses specifyInputSchema:false, so the LLM passes a single RAW STRING as the
// tool's arg. With the trigger in passthrough mode that string arrives at
// $json.query. Commands: ci_runs | recent_commits | open_prs | read_file:<path>.
const items = $input.all();
const raw = (items[0] && items[0].json) || {};
const valid = ['ci_runs', 'recent_commits', 'open_prs'];
// read_file:<path> carries an argument. Detect it on any string source first, with
// plain string ops (no regex → no JSON-escaping pitfalls). Strips leading ':'/spaces
// and leading '/'. Path may contain subdirs (slashes preserved).
const parseReadFile = (s) => {
  if (typeof s !== 'string') return null;
  const t = s.trim();
  if (t.toLowerCase().indexOf('read_file') !== 0) return null;
  let rest = t.slice(9);
  let k = 0;
  while (k < rest.length && (rest.charAt(k) === ':' || rest.charAt(k) === ' ')) k++;
  rest = rest.slice(k);
  while (rest.length && rest.charAt(0) === '/') rest = rest.slice(1);
  rest = rest.trim();
  return rest ? rest : null;
};
const _cands = [];
if (typeof raw.command === 'string') _cands.push(raw.command);
if (typeof raw.query === 'string') _cands.push(raw.query);
if (typeof raw.arguments === 'string') _cands.push(raw.arguments);
for (let _i = 0; _i < _cands.length; _i++) { const _p = parseReadFile(_cands[_i]); if (_p) return [{ json: { command: 'read_file', path: _p, _raw_input: raw } }]; }
const tryString = (s) => {
  if (typeof s !== 'string') return '';
  const t = s.trim();
  if (!t) return '';
  if (valid.indexOf(t) >= 0) return t;
  try { const p = JSON.parse(t); if (p && typeof p.command === 'string') return p.command; } catch (e) { /* ignore */ }
  return '';
};
let cmd = '';
if (typeof raw.command === 'string' && raw.command) {
  cmd = valid.indexOf(raw.command.trim()) >= 0 ? raw.command.trim() : tryString(raw.command);
} else if (typeof raw.query === 'string') {
  cmd = tryString(raw.query);
} else if (raw.query && typeof raw.query === 'object' && typeof raw.query.command === 'string') {
  cmd = raw.query.command;
} else if (raw.input && typeof raw.input.command === 'string') {
  cmd = raw.input.command;
} else if (typeof raw.arguments === 'string') {
  cmd = tryString(raw.arguments);
}
return [{ json: { command: cmd, path: '', _raw_input: raw } }];

// Reuse a cached installation token across executions to avoid minting on every
// call. Tokens live 1h; refresh only when within 5 min (300s) of expiry. The
// token is treated as an OPAQUE string — no length/format assumptions (GitHub's
// 2026 stateless tokens are ~520 chars and growing).
const sd = $getWorkflowStaticData('global');
const cache = (sd && sd.github_token_cache) || {};
const now = Math.floor(Date.now() / 1000);
const valid = !!(cache.token && cache.exp && (cache.exp - now > 300));
if (valid) {
  return [{ json: { cached: true, token: cache.token, exp: cache.exp } }];
}
return [{ json: { cached: false } }];

// Build the GitHub App JWT claims. iat backdated 60s for clock skew; exp 9 min
// (GitHub max is 10). iss is the App ID, injected at install time as a non-secret
// placeholder. The signing itself happens in the built-in JWT node (RS256 + PEM
// credential) so the n8n container does NOT need NODE_FUNCTION_ALLOW_BUILTIN=crypto.
const now = Math.floor(Date.now() / 1000);
return [{ json: { iat: now - 60, exp: now + 540, iss: '@@GITHUB_APP_ID@@' } }];

// Persist the freshly-minted installation token in workflow static data so the
// next execution reuses it (Token Cache Check). exp from GitHub's expires_at
// (ISO) → epoch seconds; fall back to now+50min if missing. Token kept opaque.
const resp = ($input.first() && $input.first().json) || {};
const token = resp.token || '';
const exp = resp.expires_at ? Math.floor(new Date(resp.expires_at).getTime() / 1000) : (Math.floor(Date.now() / 1000) + 3000);
const sd = $getWorkflowStaticData('global');
sd.github_token_cache = { token: token, exp: exp };
return [{ json: { cached: false, token: token, exp: exp } }];

// Flatten whichever GitHub branch ran into a uniform tool response, keeping
// html_url links intact (links are allowed downstream — the router egress
// allow-list permits github.com). command comes from Normalize Input. A GitHub
// REST error arrives as a single { message, documentation_url } object → ok:false.
const command = String($('Normalize Input').first().json.command || '');
const items = $input.all().map(i => i && i.json).filter(Boolean);
const firstObj = items[0] || {};
let ok = true;
let data = items;
if (firstObj && typeof firstObj.message === 'string' && (firstObj.documentation_url || firstObj.status)) {
  ok = false;
  data = firstObj;
} else if (command === 'ci_runs') {
  data = (firstObj && Array.isArray(firstObj.workflow_runs)) ? firstObj.workflow_runs : items;
} else if (command === 'read_file') {
  if (firstObj && firstObj.type === 'file' && typeof firstObj.content === 'string') {
    let content = '';
    try { content = Buffer.from(firstObj.content, 'base64').toString('utf8'); } catch (e) { content = ''; }
    let truncated = false;
    if (content.length > 16000) { content = content.slice(0, 16000); truncated = true; }
    data = { path: firstObj.path, size: firstObj.size, html_url: firstObj.html_url, truncated: truncated, content: content };
  } else if (items.length && firstObj && firstObj.type) {
    data = items.map(e => ({ name: e.name, path: e.path, type: e.type }));
  } else {
    data = firstObj;
  }
} else {
  data = items;
}
return [{ json: { ok: ok, command: command, data: data } }];
